// Integration test for the memory RPC data-plane handlers (4C-1).
//
// Provisions a space + owner, then drives the memory.* handlers through the
// registry against a real space schema (me_<slug>). Semantic search is not
// exercised (embeddings are generated by the worker — Phase 4D); fulltext
// (bm25) and filter search are.
//   TEST_DATABASE_URL="postgresql://postgres@127.0.0.1:5432/postgres" \
//     bun test --timeout 30000 \
//     packages/server/rpc/memory/memory.integration.test.ts
import { afterAll, beforeAll, beforeEach, expect, test } from "bun:test";
import {
  bootstrapSpaceDatabase,
  migrateAuth,
  migrateCore,
} from "@memory.build/database";
import type { TreeAccess } from "@memory.build/engine/core";
import * as engineCore from "@memory.build/engine/core";
import type { SpaceStore } from "@memory.build/engine/space";
import * as engineSpace from "@memory.build/engine/space";
import { type AppErrorCode, isAppError } from "@memory.build/protocol/errors";
import postgres, { type Sql } from "postgres";
import { provisionUser } from "../../provision";
import type { HandlerContext } from "../types";
import { memoryDataMethods } from "./memory";

const URL =
  process.env.TEST_DATABASE_URL ??
  "postgresql://postgres@127.0.0.1:5432/postgres";

const rand = () => {
  const a = "abcdefghijklmnopqrstuvwxyz0123456789";
  const bytes = crypto.getRandomValues(new Uint8Array(8));
  let s = "";
  for (const b of bytes) s += a[b % 36];
  return s;
};

let sql: Sql;
let authSchema: string;
let coreSchema: string;
const createdSpaceSchemas: string[] = [];

// Per-test space context.
let store: SpaceStore;
let treeAccess: TreeAccess;
let space: { id: string; slug: string };
let principalId: string;

function call<T = unknown>(
  method: string,
  params: unknown,
  ta: TreeAccess = treeAccess,
): Promise<T> {
  const registered = memoryDataMethods.get(method);
  if (!registered) throw new Error(`no handler for ${method}`);
  const context = {
    request: new Request("http://localhost/api/v1/memory/rpc"),
    store,
    core: engineCore.coreStore(sql, coreSchema),
    space,
    principalId,
    apiKeyId: null,
    treeAccess: ta,
  } as unknown as HandlerContext;
  return registered.handler(params, context) as Promise<T>;
}

/** Assert a handler call rejects with a specific AppError code. */
async function expectAppError(p: Promise<unknown>, code: AppErrorCode) {
  try {
    await p;
    throw new Error(`expected AppError(${code}), but it resolved`);
  } catch (e) {
    if (!isAppError(e)) throw e;
    expect(e.code).toBe(code);
  }
}

beforeAll(async () => {
  sql = postgres(URL, { onnotice: () => {} });
  authSchema = `auth_test_${rand()}`;
  coreSchema = `core_test_${rand()}`;
  await bootstrapSpaceDatabase(sql);
  await migrateAuth(sql, { schema: authSchema });
  await migrateCore(sql, { schema: coreSchema });
});

afterAll(async () => {
  for (const s of createdSpaceSchemas) {
    await sql.unsafe(`drop schema if exists ${s} cascade`);
  }
  await sql.unsafe(`drop schema if exists ${authSchema} cascade`);
  await sql.unsafe(`drop schema if exists ${coreSchema} cascade`);
  await sql.end();
});

// Fresh space per test so trees don't bleed across cases.
beforeEach(async () => {
  const core = engineCore.coreStore(sql, coreSchema);
  const r = await provisionUser(
    sql,
    { auth: authSchema, core: coreSchema },
    {
      email: `mem_${crypto.randomUUID().slice(0, 8)}@example.com`,
      name: "Owner",
      provider: "github",
      accountId: crypto.randomUUID(),
    },
  );
  createdSpaceSchemas.push(`me_${r.spaceSlug}`);
  store = engineSpace.spaceStore(sql, `me_${r.spaceSlug}`);
  treeAccess = await core.buildTreeAccess(r.userId, r.spaceId);
  space = { id: r.spaceId, slug: r.spaceSlug };
  principalId = r.userId;
});

test("create → get round-trips content/tree/meta and createdBy is null", async () => {
  const created = await call<{ id: string; createdBy: string | null }>(
    "memory.create",
    { content: "hello world", tree: "notes.work", meta: { tag: "a" } },
  );
  expect(created.createdBy).toBeNull();

  const got = await call<{
    id: string;
    content: string;
    tree: string;
    meta: Record<string, unknown>;
    hasEmbedding: boolean;
  }>("memory.get", { id: created.id });
  expect(got.content).toBe("hello world");
  expect(got.tree).toBe("notes.work");
  expect(got.meta).toEqual({ tag: "a" });
  expect(got.hasEmbedding).toBe(false);
});

test("create with temporal round-trips as {start,end}", async () => {
  const created = await call<{ id: string }>("memory.create", {
    content: "temporal one",
    temporal: { start: "2024-01-01T00:00:00Z", end: "2024-01-02T00:00:00Z" },
  });
  const got = await call<{ temporal: { start: string; end: string } | null }>(
    "memory.get",
    { id: created.id },
  );
  expect(got.temporal).toEqual({
    start: "2024-01-01T00:00:00.000Z",
    end: "2024-01-02T00:00:00.000Z",
  });
});

test("update patches fields", async () => {
  const created = await call<{ id: string }>("memory.create", {
    content: "before",
    tree: "a",
  });
  const updated = await call<{ content: string; tree: string }>(
    "memory.update",
    { id: created.id, content: "after", tree: "a.b" },
  );
  expect(updated.content).toBe("after");
  expect(updated.tree).toBe("a.b");
});

test("delete removes; get then NOT_FOUND", async () => {
  const created = await call<{ id: string }>("memory.create", {
    content: "doomed",
  });
  const res = await call<{ deleted: boolean }>("memory.delete", {
    id: created.id,
  });
  expect(res.deleted).toBe(true);
  await expectAppError(call("memory.get", { id: created.id }), "NOT_FOUND");
});

test("get / delete unknown id → NOT_FOUND", async () => {
  const ghost = crypto.randomUUID();
  await expectAppError(call("memory.get", { id: ghost }), "NOT_FOUND");
  await expectAppError(call("memory.delete", { id: ghost }), "NOT_FOUND");
});

test("batchCreate inserts all and is retrievable", async () => {
  const res = await call<{ ids: string[] }>("memory.batchCreate", {
    memories: [
      { content: "one", tree: "batch" },
      { content: "two", tree: "batch" },
      { content: "three", tree: "batch.sub" },
    ],
  });
  expect(res.ids).toHaveLength(3);
  const count = await call<{ count: number }>("memory.countTree", {
    tree: "batch",
  });
  expect(count.count).toBe(3);
});

test("tree returns descendant node counts under a path", async () => {
  await call("memory.batchCreate", {
    memories: [
      { content: "x", tree: "root.a" },
      { content: "y", tree: "root.a.deep" },
      { content: "z", tree: "root.b" },
    ],
  });
  const res = await call<{ nodes: { path: string; count: number }[] }>(
    "memory.tree",
    { tree: "root" },
  );
  const byPath = Object.fromEntries(res.nodes.map((n) => [n.path, n.count]));
  expect(byPath["root.a"]).toBe(2);
  expect(byPath["root.a.deep"]).toBe(1);
  expect(byPath["root.b"]).toBe(1);
  // the base path itself is excluded
  expect(byPath.root).toBeUndefined();
});

test("tree respects levels depth limit", async () => {
  await call("memory.batchCreate", {
    memories: [{ content: "deep", tree: "t.a.b.c" }],
  });
  const res = await call<{ nodes: { path: string }[] }>("memory.tree", {
    tree: "t",
    levels: 1,
  });
  const paths = res.nodes.map((n) => n.path);
  expect(paths).toContain("t.a");
  expect(paths).not.toContain("t.a.b");
});

test("move relocates a subtree (dryRun counts without moving)", async () => {
  await call("memory.batchCreate", {
    memories: [
      { content: "m1", tree: "src.x" },
      { content: "m2", tree: "src.y" },
    ],
  });
  const dry = await call<{ count: number }>("memory.move", {
    source: "src",
    destination: "dst",
    dryRun: true,
  });
  expect(dry.count).toBe(2);
  // still under src
  expect(
    (await call<{ count: number }>("memory.countTree", { tree: "src" })).count,
  ).toBe(2);

  const moved = await call<{ count: number }>("memory.move", {
    source: "src",
    destination: "dst",
  });
  expect(moved.count).toBe(2);
  expect(
    (await call<{ count: number }>("memory.countTree", { tree: "src" })).count,
  ).toBe(0);
  expect(
    (await call<{ count: number }>("memory.countTree", { tree: "dst" })).count,
  ).toBe(2);
});

test("deleteTree removes a subtree (dryRun counts without deleting)", async () => {
  await call("memory.batchCreate", {
    memories: [
      { content: "d1", tree: "gone.a" },
      { content: "d2", tree: "gone.b" },
    ],
  });
  const dry = await call<{ count: number }>("memory.deleteTree", {
    tree: "gone",
    dryRun: true,
  });
  expect(dry.count).toBe(2);
  const del = await call<{ count: number }>("memory.deleteTree", {
    tree: "gone",
  });
  expect(del.count).toBe(2);
  expect(
    (await call<{ count: number }>("memory.countTree", { tree: "gone" })).count,
  ).toBe(0);
});

test("search: fulltext (bm25) finds matching content", async () => {
  await call("memory.batchCreate", {
    memories: [
      { content: "the quick brown fox", tree: "s" },
      { content: "lazy dogs sleep", tree: "s" },
    ],
  });
  const res = await call<{ results: { content: string }[]; total: number }>(
    "memory.search",
    { fulltext: "fox" },
  );
  expect(res.total).toBeGreaterThanOrEqual(1);
  expect(res.results.some((r) => r.content.includes("fox"))).toBe(true);
});

test("search: tree filter only (no ranking) returns matches", async () => {
  await call("memory.batchCreate", {
    memories: [
      { content: "in scope", tree: "scope.a" },
      { content: "out of scope", tree: "other" },
    ],
  });
  const res = await call<{ results: { tree: string }[] }>("memory.search", {
    tree: "scope",
  });
  expect(res.results.length).toBe(1);
  expect(res.results[0]?.tree).toBe("scope.a");
});

test("search: grep alone is rejected", async () => {
  await expectAppError(
    call("memory.search", { grep: "anything" }),
    "VALIDATION_ERROR",
  );
});

test("search: semantic without embedding config → EMBEDDING_NOT_CONFIGURED", async () => {
  await expectAppError(
    call("memory.search", { semantic: "meaning" }),
    "EMBEDDING_NOT_CONFIGURED",
  );
});

test("create without write access → FORBIDDEN", async () => {
  // read-only on the root path
  const readOnly: TreeAccess = [
    { tree_path: "", access: engineCore.ACCESS.read },
  ];
  await expectAppError(
    call("memory.create", { content: "nope", tree: "x" }, readOnly),
    "FORBIDDEN",
  );
});
